Dear New Yorker reader, take advantage of this special limited-time offer.* *  div { margin:0 !important; }
body {
width: 100%;
background-color: #ffffff;
margin: 0 auto !important;
padding: 0;
-webkit-font-smoothing: antialiased;
}

.appleLinks a
{
color: #000000;
text-decoration: none;
}

table
{
border-spacing: 0;
font-family: sans-serif;
color: #333333;
}

table[align="center"] {margin: 0 auto;}
td { padding: 0; margin: 0 auto;}
img { border: 0; }
div[style*="margin: 16px 0"] { margin: 0 !important; }
[style*=futura-pt] {
font-family: futura-pt,Helvetica Neue, Helvetica, Arial, sans-serif !important;
mso-font-alt: Helvetica Neue, Helvetica, Arial, sans-serif !important;
}

.wrapper
{
width: 100%;
table-layout: fixed;
-webkit-text-size-adjust: 100%;
-ms-text-size-adjust: 100%;
}

.webkit
{
max-width: 600px;
margin: 0 auto;
background-color: #ffffff;
}

.outer
{
Margin: 0 auto;
width: 100%;
max-width: 600px;
}

.full-width-image img
{
width: 100%;
max-width: 600px;
height: auto;
}
.subscribe-button{
width: 285px;
height: 58px;
background-color: #000000;
}
.one-column .contents { text-align: left; }

.button { max-width: 210px; }

.right-sidebar
{
text-align: left;
font-size: 0;
}

.right-sidebar .column
{
width: 100%;
display: inline-block;
vertical-align: top;
}

.right-sidebar .left { max-width: 365px; }
.right-sidebar .right { max-width: 270px; }

.right-sidebar .img
{
width: 100%;
max-width: 270px;
height: auto;
margin: 0 auto;
text-align: center;
}

.right-sidebar .contents
{
font-size: 14px;
text-align: center;
}

@media only screen and (max-width: 590px)
{
td[class="body-copy"] { padding: 20px 20px 0 !important; }
td[class="header"] { padding: 20px 10px !important; }

td[class="footer"]
{
padding: 15px 50px !important;
font-size: 9px !important;
line-height: 12px !important;
}

